/**
 * 参数校验函数
 * @param {Object} input - 待校验的对象
 * @returns {Object} - 校验结果，包含是否通过和错误信息
 */
function validateInput(input) {
    const errors = [];

    // 校验 user_id 字段
    if (!input.hasOwnProperty('user_id')) {
        errors.push("缺少字段: user_id");
    } else if (typeof input.user_id !== 'number') {
        errors.push("字段 user_id 类型错误，应为数字");
    }

    // 校验 procedure_id 字段
    // if (!input.hasOwnProperty('procedure_id')) {
    //     errors.push("缺少字段: procedure_id");
    // } else if (typeof input.procedure_id !== 'number') {
    //     errors.push("字段 procedure_id 类型错误，应为数字");
    // }

    // 校验 machine_id 字段
    if (!input.hasOwnProperty('machine_id')) {
        errors.push("缺少字段: machine_id");
    } else if (typeof input.machine_id !== 'number') {
        errors.push("字段 machine_id 类型错误，应为数字");
    }

    // 校验 history_procedure_id 字段
    // if (!input.hasOwnProperty('history_procedure_id')) {
    //     errors.push("缺少字段: history_procedure_id");
    // } else if (typeof input.history_procedure_id !== 'number') {
    //     errors.push("字段 history_procedure_id 类型错误，应为数字");
    // }

    // 校验 data 字段
    if (!input.hasOwnProperty('data')) {
        errors.push("缺少字段: data");
    } else if (typeof input.data !== 'object' || input.data === null) {
        errors.push("字段 data 类型错误，应为非空对象");
    }

    // 校验 retroid 字段
    if (!input.hasOwnProperty('retroid')) {
        errors.push("缺少字段: retroid");
    } else if (typeof input.retroid !== 'string') {
        errors.push("字段 retroid 类型错误，应为字符串");
    }
  const { weight, boxId } = input.data;
  input.data.bind_id = weight ?? boxId;
    // 返回校验结果
    return {
        isValid: errors.length === 0,
          errors: errors,
          req:input
    };
}



